import { ClassicPreset, NodeEditor } from 'https://cdn.jsdelivr.net/npm/rete@2/+esm'; import { AreaExtensions, AreaPlugin } from 'https://cdn.jsdelivr.net/npm/rete-area-plugin@2/+esm';
