const el = document.getElementById('rete'); el.style.height = '480px'; const editor = new NodeEditor(); const area = new AreaPlugin(el); const render = new LitPlugin(); render.addPreset(LitPresets.classic.setup()); const wire = new ConnectionPlugin(); wire.addPreset(ConnectionPresets.classic.setup()); editor.use(area); area.use(wire); area.use(render);
